#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1000005;
ll n,m,k,rt1,rt2,a[N],mn[N],mx[N],cnt[N];
vector<int> g[N];
void dfs(int u,int f)
{
	for(int i=0;i<g[u].size();i++) 
	{
		int v=g[u][i];
		if(v==f) continue;
		mn[v]=mn[u]*(cnt[u]-1);
		mx[v]=(mx[u]+1)*(cnt[u]-1)-1;
		mn[v]=min(mn[v],(ll)1e10);
		mx[v]=min(mx[v],(ll)1e10);
		dfs(v,u);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>k;
	for(int i=1;i<=m;i++)
	{
		cin>>a[i];
	}
	sort(a+1,a+1+m);
	cin>>rt1>>rt2;
	cnt[0]=2;
	cnt[rt1]=cnt[rt2]=1;
	g[0].push_back(rt1);
	g[0].push_back(rt2);
	g[rt1].push_back(0);
	g[rt2].push_back(0);
	for(int i=1;i<=n-2;i++)
	{
		int x,y;
		cin>>x>>y;
		g[x].push_back(y);
		g[y].push_back(x);
		cnt[x]++;
		cnt[y]++;
	}
	mn[0]=mx[0]=k;
	dfs(0,-1);
	ll ans=0;
	for(int i=1;i<=n;i++)
	{
		if(cnt[i]==1)
		{
			auto r=upper_bound(a+1,a+1+m,mx[i]);
			auto l=lower_bound(a+1,a+1+m,mn[i]);
			ans+=(r-l);
		}
	}
	cout<<ans*k;
	return 0;
}
